from http.server import BaseHTTPRequestHandler
import json
import base64
import io
import joblib
import numpy as np

DATOS = {'medianas': {'gender': 1.0, 'age': 40.0, 'height(cm)': 165.0, 'weight(kg)': 65.0, 'waist(cm)': 3.4166666666666665, 'eyesight(left)': 0.0416666666666666, 'eyesight(right)': 0.0416666666666666, 'hearing(left)': 0.0416666666666666, 'hearing(right)': 0.0416666666666666, 'systolic': 5.0, 'relaxation': 3.1666666666666665, 'fasting blood sugar': 4.0, 'Cholesterol': 8.125, 'triglyceride': 4.5, 'HDL': 2.2916666666666665, 'LDL': 4.708333333333333, 'hemoglobin': 0.5888888888888889, 'Urine protein': 0.0416666666666666, 'serum creatinine': 0.0062499999999999, 'AST': 0.9583333333333334, 'ALT': 0.875, 'Gtp': 1.0416666666666667, 'dental caries': 0.0, 'tartar': 1.0}, 'columnas': ['gender', 'age', 'height(cm)', 'weight(kg)', 'waist(cm)', 'eyesight(left)', 'eyesight(right)', 'hearing(left)', 'hearing(right)', 'systolic', 'relaxation', 'fasting blood sugar', 'Cholesterol', 'triglyceride', 'HDL', 'LDL', 'hemoglobin', 'Urine protein', 'serum creatinine', 'AST', 'ALT', 'Gtp', 'dental caries', 'tartar'], 'umbral': 0.39}

MODELO_B64 = """"""

modelo = joblib.load(io.BytesIO(base64.b64decode(MODELO_B64)))


class handler(BaseHTTPRequestHandler):
    def do_POST(self):
        length = int(self.headers.get("Content-Length", 0))
        body = json.loads(self.rfile.read(length) or "{}")
        persona = dict(DATOS["medianas"])
        for k, v in body.items():
            if k in persona:
                persona[k] = float(v)
        fila = [persona[c] for c in DATOS["columnas"]]
        X = np.array([fila], dtype=float)
        prob = float(modelo.predict_proba(X)[0, 1])
        self.send_response(200)
        self.send_header("Content-Type", "application/json")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        salida = {"probabilidad": prob, "fuma": prob >= DATOS["umbral"]}
        self.wfile.write(json.dumps(salida).encode())
